import React, { useContext } from 'react';
import { AppContext } from '../context/AppContext';

const CatalogPage = () => {
  const { products, user, createOrder } = useContext(AppContext);

  return (
    <div className="container">
      <h1 style={{marginBottom: '30px'}}>Каталог кроссовок</h1>
      <div className="product-grid">
        {products.map(p => (
          <div key={p.id} className="card">
            <img src={p.img} alt={p.name} style={{width: '100%', borderRadius: '10px'}} />
            <h3>{p.name}</h3>
            <p>{p.price.toLocaleString()} KZT</p>
            {user ? (
              <button onClick={() => createOrder([p])}>Купить сейчас</button>
            ) : (
              <p style={{fontSize: '0.9rem', color: '#888'}}>Войдите, чтобы совершить покупку</p>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};
export default CatalogPage;
